import { useEffect, useState } from 'react';

declare global {
  interface Window {
    __LINM_ENABLE_MESSAGE__?: boolean;
    __LINM_ENABLE_NOTIFICATION__?: boolean;
  }
}

export interface ShellTopbarFlags {
  enableMessage: boolean;
  enableNotification: boolean;
}

function readShellTopbarFlags(): ShellTopbarFlags {
  if (typeof window === 'undefined') {
    return { enableMessage: false, enableNotification: false };
  }

  const hasRootRuntime =
    window.__LINM_ENABLE_MESSAGE__ !== undefined ||
    window.__LINM_ENABLE_NOTIFICATION__ !== undefined;

  if (hasRootRuntime) {
    return {
      enableMessage: window.__LINM_ENABLE_MESSAGE__ === true,
      enableNotification: window.__LINM_ENABLE_NOTIFICATION__ === true,
    };
  }

  return {
    enableMessage: import.meta.env.VITE_ENABLE_MESSAGE === 'true',
    enableNotification:
      import.meta.env.VITE_ENABLE_NOTIFICATION === 'true',
  };
}

/** Root runtime SSOT for topbar message/notification slots (falls back to build env in standalone dev). */
export function useShellTopbarFlags(): ShellTopbarFlags {
  const [flags, setFlags] = useState(readShellTopbarFlags);

  useEffect(() => {
    const sync = () => setFlags(readShellTopbarFlags());
    sync();
    const timer = window.setTimeout(sync, 0);
    window.addEventListener('single-spa:routing-event', sync);
    return () => {
      window.clearTimeout(timer);
      window.removeEventListener('single-spa:routing-event', sync);
    };
  }, []);

  return flags;
}
