const trim = (value?: string) => (value ?? '').trim();

/** Default in-app icon — Linm.Web.Root/public/icons/logo-128.png */
export const SHELL_ICON_PATH = '/icons/logo-128.png';

export type ShellBrandingSnapshot = {
  title?: string;
  subTitle?: string;
  icon?: string;
  iconFolder?: string;
  navMain?: string;
};

declare global {
  interface Window {
    __LINM_SHELL_BRANDING__?: ShellBrandingSnapshot;
  }
}

export function normalizeIconFolder(raw?: string): string {
  let v = trim(raw).replace(/^\/+|\/+$/g, '');
  if (v.toLowerCase().startsWith('icons/')) v = v.slice(6);
  if (!v || v.includes('..') || v.includes('/')) return '';
  return v;
}

export function shellInAppIconUrl(folder?: string, file = 'logo-128.png'): string {
  const f = normalizeIconFolder(folder);
  return f ? `/icons/${f}/${file}` : `/icons/${file}`;
}

function readRootShellBranding(): ShellBrandingSnapshot | undefined {
  if (typeof window === 'undefined') return undefined;
  const value = window.__LINM_SHELL_BRANDING__;
  return value && typeof value === 'object' ? value : undefined;
}

export const shellBranding = {
  title: trim(import.meta.env.VITE_TITLE as string) || 'LINM ERP',
  subTitle: trim(import.meta.env.VITE_SUB_TITLE as string) || 'Hệ Thống Quản Trị Doanh Nghiệp',
  iconFolder: normalizeIconFolder(import.meta.env.VITE_ICON_FOLDER as string),
  navMain: trim(import.meta.env.VITE_NAV_MAIN as string) || 'Linm',
} as const;

export function resolveShellIcon(): string {
  const fromRoot = readRootShellBranding();
  const rootIcon = trim(fromRoot?.icon);
  if (rootIcon) return rootIcon;
  const rootFolder = normalizeIconFolder(fromRoot?.iconFolder);
  if (rootFolder) return shellInAppIconUrl(rootFolder);
  if (shellBranding.iconFolder) return shellInAppIconUrl(shellBranding.iconFolder);
  return SHELL_ICON_PATH;
}

export function resolveShellNavMain(): string {
  const fromRoot = trim(readRootShellBranding()?.navMain);
  if (fromRoot) return fromRoot;
  return shellBranding.navMain;
}

/** Sidebar logo label — white-label only (iconFolder set on Root snapshot). */
export function resolveShellLogoLabel(): string | undefined {
  const root = readRootShellBranding();
  const folder = normalizeIconFolder(root?.iconFolder);
  if (!folder && !trim(root?.icon)) return undefined;
  const nav = trim(root?.navMain);
  if (nav) return nav;
  return resolveShellNavMain();
}

export function resolveShellTitle(): string {
  const fromRoot = trim(readRootShellBranding()?.title);
  if (fromRoot) return fromRoot;
  return shellBranding.title;
}

export function resolveShellSubTitle(): string {
  const fromRoot = trim(readRootShellBranding()?.subTitle);
  if (fromRoot) return fromRoot;
  return shellBranding.subTitle;
}
