import React, { useEffect, useRef, useState } from 'react';
import {
  SwitchCompanyModal,
  getActiveCompanyCode,
  getAuthUser,
  normCompanyCode,
  setActiveCompanyCode,
  useActiveCompany,
} from '@linm-soft-org/linm-web-common-components';
import styles from './NavTopbarActions.module.css';

interface NavSwitchCompanyButtonProps {
  isMobile: boolean;
}

const LEGACY_DEV_COMPANY_GUID = '11111111-1111-1111-1111-111111111111';

function isGuidTenantKey(value: string): boolean {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value.trim());
}

function setActiveCompanyIfChanged(companyCode: string): void {
  const next = normCompanyCode(companyCode);
  const current = getActiveCompanyCode();
  if (current === next) return;
  setActiveCompanyCode(next);
}

/** Migrate Guid in secure storage → tenant id (LINM dev default). Runs once on mount. */
function migrateLegacyStoredCompany(homeTenantKey?: string | null): void {
  const stored = getActiveCompanyCode();
  const home = homeTenantKey?.trim().toUpperCase();
  const fallback =
    home && !isGuidTenantKey(home)
      ? home
      : 'LINM';

  if (stored && isGuidTenantKey(stored)) {
    setActiveCompanyIfChanged(fallback);
    return;
  }
  if (!stored && home && !isGuidTenantKey(home)) {
    setActiveCompanyIfChanged(home);
    return;
  }
  if (stored?.toLowerCase() === LEGACY_DEV_COMPANY_GUID) {
    setActiveCompanyIfChanged(fallback);
  }
}

/** Switch-company button + anchored popover — shows Mã chi nhánh đang làm việc. */
export const NavSwitchCompanyButton: React.FC<NavSwitchCompanyButtonProps> = ({ isMobile }) => {
  const [isOpen, setIsOpen] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const { label, loading } = useActiveCompany();

  useEffect(() => {
    migrateLegacyStoredCompany(getAuthUser()?.companyCode ?? undefined);
  }, []);

  const displayCode = label ?? '…';

  return (
    <>
      <button
        ref={buttonRef}
        type="button"
        className={styles.switchCompanyBtn}
        onClick={() => setIsOpen((open) => !open)}
        title={`Đơn vị cơ sở: ${displayCode}`}
        aria-label={`Đơn vị cơ sở đang làm việc: ${displayCode}. Nhấn để chuyển đổi.`}
        aria-expanded={isOpen}
        aria-haspopup="dialog"
        data-testid="nav-switch-company-btn"
      >
        <i className="fas fa-building" />
        {!isMobile && (
          <span className={styles.switchCompanyLabel}>
            {loading ? '…' : displayCode}
          </span>
        )}
      </button>
      <SwitchCompanyModal
        isOpen={isOpen}
        onClose={() => setIsOpen(false)}
        anchorRef={buttonRef}
      />
    </>
  );
};
